import React, { useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import Webcam from 'react-webcam';
import axios from 'axios';

const CameraUpload = () => {
  const navigate = useNavigate();
  const webcamRef = useRef(null);
  const [showCamera, setShowCamera] = useState(false);
  const [currentFace, setCurrentFace] = useState(null);
  const [loading, setLoading] = useState(false);

  const [cubeState, setCubeState] = useState({
    U: Array(9).fill('white'),
    D: Array(9).fill('yellow'),
    L: Array(9).fill('orange'),
    R: Array(9).fill('red'),
    F: Array(9).fill('green'),
    B: Array(9).fill('blue')
  });

  const faceLabels = { U: 'UP', D: 'DOWN', L: 'LEFT', R: 'RIGHT', F: 'FRONT', B: 'BACK' };

  const openCameraForFace = (face) => {
    setCurrentFace(face);
    setShowCamera(true);
  };

  const capturePhoto = async () => {
    const imageSrc = webcamRef.current.getScreenshot();

    if (!imageSrc) {
      alert('Camera capture failed');
      return;
    }

    setShowCamera(false);
    setLoading(true);

    try {
      const res = await axios.post('http://localhost:8000/api/detect-face/', {
        image: imageSrc,
        face: currentFace
      });

      if (res.data.success) {
        setCubeState(prev => ({
          ...prev,
          [currentFace]: res.data.colors
        }));
      } else {
        alert(res.data.error);
      }
    } catch (err) {
      console.log(err);
      alert('Failed to detect face. Please try again.');
    } finally {
      setLoading(false);
      setCurrentFace(null);
    }
  };

  const handleSubmit = async () => {
    setLoading(true);
    try {
      const res = await axios.post('http://localhost:8000/solve/', cubeState);

      if (res.data.success) {
        navigate('/solve', {
          state: { solution: res.data.solution, cubeState }
        });
      } else {
        alert(res.data.error);
      }
    } catch {
      alert('Failed to solve cube.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div>
      {showCamera && (
        <div>
          <Webcam ref={webcamRef} screenshotFormat="image/jpeg" />
          <button onClick={capturePhoto}>Capture</button>
        </div>
      )}

      {Object.keys(cubeState).map(face => (
        <button key={face} onClick={() => openCameraForFace(face)}>
          Capture {faceLabels[face]}
        </button>
      ))}

      <button onClick={handleSubmit}>
        {loading ? 'Solving...' : 'Solve Cube'}
      </button>
    </div>
  );
};

export default CameraUpload;
